 17→package com.fsck.k9.mail.helper;
 18→
 19→
 20→import java.util.ArrayList;
 21→import java.util.Collection;
 22→
 23→/**
 24→ * This class works as a Tokenizer for MultiAutoCompleteTextView for
 25→ * address list fields, and also provides a method for converting
 26→ * a string of addresses (such as might be typed into such a field)
 27→ * into a series of Rfc822Tokens.
 28→ */
 29→public class Rfc822Tokenizer {
 30→
 31→    /**
 32→     * This constructor will try to take a string like
 33→     * "Foo Bar (something) &lt;foo\@google.com&gt;,
 34→     * blah\@google.com (something)"
 35→     * and convert it into one or more Rfc822Tokens, output into the supplied
 36→     * collection.
 37→     *
 38→     * It does *not* decode MIME encoded-words; charset conversion
 39→     * must already have taken place if necessary.
 40→     * It will try to be tolerant of broken syntax instead of
 41→     * returning an error.
 42→     *
 43→     */
 44→    public static void tokenize(CharSequence text, Collection<Rfc822Token> out) {
 45→        StringBuilder name = new StringBuilder();
 46→        StringBuilder address = new StringBuilder();
 47→        StringBuilder comment = new StringBuilder();
 48→
 49→        int i = 0;
 50→        int cursor = text.length();
 51→
 52→        while (i < cursor) {
 53→            char c = text.charAt(i);
 54→
 55→            if (c == ',' || c == ';') {
 56→                i++;
 57→
 58→                while (i < cursor && text.charAt(i) == ' ') {
 59→                    i++;
 60→                }
 61→
 62→                crunch(name);
 63→
 64→                if (address.length() > 0) {
 65→                    out.add(new Rfc822Token(name.toString(),
 66→                            address.toString(),
 67→                            comment.toString()));
 68→                } else if (name.length() > 0) {
 69→                    out.add(new Rfc822Token(null,
 70→                            name.toString(),
 71→                            comment.toString()));
 72→                }
 73→
 74→                name.setLength(0);
 75→                address.setLength(0);
 76→                comment.setLength(0);
 77→            } else if (c == '"') {
 78→                i++;
 79→
 80→                while (i < cursor) {
 81→                    c = text.charAt(i);
 82→
 83→                    if (c == '"') {
 84→                        i++;
 85→                        break;
 86→                    } else if (c == '\\') {
 87→                        if (i + 1 < cursor) {
 88→                            name.append(text.charAt(i + 1));
 89→                        }
 90→                        i += 2;
 91→                    } else {
 92→                        name.append(c);
 93→                        i++;
 94→                    }
 95→                }
 96→            } else if (c == '(') {
 97→                int level = 1;
 98→                i++;
 99→
100→                while (i < cursor && level > 0) {
101→                    c = text.charAt(i);
102→
103→                    if (c == ')') {
104→                        if (level > 1) {
105→                            comment.append(c);
106→                        }
107→
108→                        level--;
109→                        i++;
110→                    } else if (c == '(') {
111→                        comment.append(c);
112→                        level++;
113→                        i++;
114→                    } else if (c == '\\') {
115→                        if (i + 1 < cursor) {
116→                            comment.append(text.charAt(i + 1));
117→                        }
118→                        i += 2;
119→                    } else {
120→                        comment.append(c);
121→                        i++;
122→                    }
123→                }
124→            } else if (c == '<') {
125→                i++;
126→
127→                while (i < cursor) {
128→                    c = text.charAt(i);
129→
130→                    if (c == '>') {
131→                        i++;
132→                        break;
133→                    } else {
134→                        address.append(c);
135→                        i++;
136→                    }
137→                }
138→            } else if (c == ' ') {
139→                name.append('\0');
140→                i++;
141→            } else {
142→                name.append(c);
143→                i++;
144→            }
145→        }
146→
147→        crunch(name);
148→
149→        if (address.length() > 0) {
150→            out.add(new Rfc822Token(name.toString(),
151→                    address.toString(),
152→                    comment.toString()));
153→        } else if (name.length() > 0) {
154→            out.add(new Rfc822Token(null,
155→                    name.toString(),
156→                    comment.toString()));
157→        }
158→    }
159→
160→    /**
161→     * This method will try to take a string like
162→     * "Foo Bar (something) &lt;foo\@google.com&gt;,
163→     * blah\@google.com (something)"
164→     * and convert it into one or more Rfc822Tokens.
165→     * It does *not* decode MIME encoded-words; charset conversion
166→     * must already have taken place if necessary.
167→     * It will try to be tolerant of broken syntax instead of
168→     * returning an error.
169→     */
170→    public static Rfc822Token[] tokenize(CharSequence text) {
171→        ArrayList<Rfc822Token> out = new ArrayList<Rfc822Token>();
172→        tokenize(text, out);
173→        return out.toArray(new Rfc822Token[out.size()]);
174→    }
175→
176→    private static void crunch(StringBuilder sb) {
177→        int i = 0;
178→        int len = sb.length();
179→
180→        while (i < len) {
181→            char c = sb.charAt(i);
182→
183→            if (c == '\0') {
184→                if (i == 0 || i == len - 1 ||
185→                        sb.charAt(i - 1) == ' ' ||
186→                        sb.charAt(i - 1) == '\0' ||
187→                        sb.charAt(i + 1) == ' ' ||
188→                        sb.charAt(i + 1) == '\0') {
189→                    sb.deleteCharAt(i);
190→                    len--;
191→                } else {
192→                    i++;
193→                }
194→            } else {
195→                i++;
196→            }
197→        }
198→
199→        for (i = 0; i < len; i++) {
200→            if (sb.charAt(i) == '\0') {
201→                sb.setCharAt(i, ' ');
202→            }
203→        }
204→    }
205→
206→    /**
207→     * {@inheritDoc}
208→     */
209→    public int findTokenStart(CharSequence text, int cursor) {
210→        /*
211→         * It's hard to search backward, so search forward until
212→         * we reach the cursor.
213→         */
214→
215→        int best = 0;
216→        int i = 0;
217→
218→        while (i < cursor) {
219→            i = findTokenEnd(text, i);
220→
221→            if (i < cursor) {
222→                i++; // Skip terminating punctuation
223→
224→                while (i < cursor && text.charAt(i) == ' ') {
225→                    i++;
226→                }
227→
228→                if (i < cursor) {
229→                    best = i;
230→                }
231→            }
232→        }
233→
234→        return best;
235→    }
236→
237→    /**
238→     * {@inheritDoc}
239→     */
240→    public int findTokenEnd(CharSequence text, int cursor) {
241→        int len = text.length();
242→        int i = cursor;
243→
244→        while (i < len) {
245→            char c = text.charAt(i);
246→
247→            if (c == ',' || c == ';') {
248→                return i;
249→            } else if (c == '"') {
250→                i++;
251→
252→                while (i < len) {
253→                    c = text.charAt(i);
254→
255→                    if (c == '"') {
256→                        i++;
257→                        break;
258→                    } else if (c == '\\' && i + 1 < len) {
259→                        i += 2;
260→                    } else {
261→                        i++;
262→                    }
263→                }
264→            } else if (c == '(') {
265→                int level = 1;
266→                i++;
267→
268→                while (i < len && level > 0) {
269→                    c = text.charAt(i);
270→
271→                    if (c == ')') {
272→                        level--;
273→                        i++;
274→                    } else if (c == '(') {
275→                        level++;
276→                        i++;
277→                    } else if (c == '\\' && i + 1 < len) {
278→                        i += 2;
279→                    } else {
280→                        i++;
281→                    }
282→                }
283→            } else if (c == '<') {
284→                i++;
285→
286→                while (i < len) {
287→                    c = text.charAt(i);
288→
289→                    if (c == '>') {
290→                        i++;
291→                        break;
292→                    } else {
293→                        i++;
294→                    }
295→                }
296→            } else {
297→                i++;
298→            }
299→        }
300→
301→        return i;
302→    }
303→
304→    /**
305→     * Terminates the specified address with a comma and space.
306→     * This assumes that the specified text already has valid syntax.
307→     * The Adapter subclass's convertToString() method must make that
308→     * guarantee.
309→     */
310→    public CharSequence terminateToken(CharSequence text) {
311→        return text + ", ";
312→    }
313→}
