500→    /**
501→     * Changing the size of our RecipientTokenSpan doesn't seem to redraw the cursor in the new position. This will
502→     * make sure the cursor position is recalculated.
503→     */
504→    private void invalidateCursorPositionHack() {
505→        int oldStart = getSelectionStart();
506→        int oldEnd = getSelectionEnd();
507→
508→        // The selection values need to actually change in order for the cursor to be redrawn. If the cursor already
509→        // is at position 0 this won't trigger a redraw. But that's fine because the size of our span can't influence
510→        // cursor position 0.
511→        setSelection(0);
512→
513→        setSelection(oldStart, oldEnd);
