 52→    private static final String[] PROJECTION = {
 53→            ContactsContract.CommonDataKinds.Email._ID,
 54→            ContactsContract.Contacts.DISPLAY_NAME_PRIMARY,
 55→            ContactsContract.Contacts.LOOKUP_KEY,
