 62→            ContactsContract.Contacts.SORT_KEY_PRIMARY,
 63→            ContactsContract.Contacts.STARRED,
 64→    };
 65→
 66→    private static final String SORT_ORDER = "" +
 67→            ContactsContract.CommonDataKinds.Email.TIMES_CONTACTED + " DESC, " +
 68→            ContactsContract.Contacts.SORT_KEY_PRIMARY + "," +
 69→            ContactsContract.CommonDataKinds.Email.IS_SUPER_PRIMARY + " DESC, " +
 70→            ContactsContract.CommonDataKinds.Email.IS_PRIMARY + " DESC, " +
 71→            ContactsContract.Contacts._ID;
