 99→    private static final Comparator<Recipient> RECIPIENT_COMPARATOR = new Comparator<Recipient>() {
100→        @Override
101→        public int compare(Recipient lhs, Recipient rhs) {
102→            if (rhs.starred != lhs.starred) {
103→                return rhs.starred ? 1 : -1;
104→            }
105→
106→            int timesContactedDiff = rhs.timesContacted - lhs.timesContacted;
107→            if (timesContactedDiff != 0) {
108→                return timesContactedDiff;
109→            }
110→
111→            if (lhs.sortKey == null && rhs.sortKey == null) {
112→                return 0;
113→            } else if (lhs.sortKey == null) {
114→                return 1;
115→            } else if (rhs.sortKey == null) {
116→                return -1;
117→            }
118→
119→            return CASE_INSENSITIVE_ORDER.compare(lhs.sortKey, rhs.sortKey);
120→        }
121→    };
