225→    private void fillContactDataFromCryptoProvider(String query, List<Recipient> recipients,
226→            Map<String, Recipient> recipientMap) {
227→        Cursor cursor;
228→        try {
229→            Uri queryUri = Uri.parse("content://" + cryptoProvider + ".provider.exported/autocrypt_status");
230→            cursor = contentResolver.query(queryUri, PROJECTION_CRYPTO_ADDRESSES, null,
231→                    new String[] { "%" + query + "%" }, null);
232→
233→            if (cursor == null) {
234→                return;
235→            }
236→        } catch (Exception e) {
237→            Timber.e(e, "Couldn't obtain recipients from crypto provider!");
238→            return;
239→        }
240→
241→        while (cursor.moveToNext()) {
242→            String uid = cursor.getString(INDEX_USER_ID);
243→            Address[] addresses = Address.parseUnencoded(uid);
244→
245→            for (Address address : addresses) {
246→                String emailAddress = address.getAddress();
247→                if (!isSupportedEmailAddress(emailAddress) || recipientMap.containsKey(emailAddress)) {
248→                    continue;
249→                }
250→
251→                Recipient recipient = new Recipient(address);
252→                recipients.add(recipient);
253→                recipientMap.put(emailAddress, recipient);
254→            }
255→        }
256→
257→        cursor.close();
258→    }
