272→    private void fillContactDataFromEmailContentUri(Uri contactUri, List<Recipient> recipients,
273→            Map<String, Recipient> recipientMap) {
274→        Cursor cursor = contentResolver.query(contactUri, PROJECTION, null, null, null);
275→
276→        if (cursor == null) {
277→            return;
278→        }
279→
280→        fillContactDataFromCursor(cursor, recipients, recipientMap);
