317→    private Cursor getNicknameCursor(String nickname) {
318→        nickname = "%" + nickname + "%";
319→
320→        Uri queryUriForNickname = ContactsContract.Data.CONTENT_URI;
321→
322→
323→        if (hasContactPermission()) {
324→            return contentResolver.query(queryUriForNickname,
325→                    PROJECTION_NICKNAME,
326→                    ContactsContract.CommonDataKinds.Nickname.NAME + " LIKE ? AND " +
327→                            Data.MIMETYPE + " = ?",
328→                    new String[] { nickname, ContactsContract.CommonDataKinds.Nickname.CONTENT_ITEM_TYPE },
329→                    null);
