389→    private List<Recipient> fillContactDataBySortOrder(int maxRecipients) {
390→        List<Recipient> recipients = new ArrayList<>();
391→
392→        Uri queryUri = Email.CONTENT_URI;
393→
394→        Cursor cursor = null;
395→        if (hasContactPermission()) {
396→            cursor = contentResolver.query(queryUri, PROJECTION, null, null, SORT_ORDER);
397→        }
398→
399→        if (cursor == null) {
400→            return recipients;
401→        }
402→
403→        fillContactDataFromCursor(cursor, recipients, new HashMap<>(), maxRecipients);
404→
405→        return recipients;
406→    }
