409→    private boolean fillContactDataFromNameAndEmail(String query, List<Recipient> recipients,
410→            Map<String, Recipient> recipientMap, Integer maxTargets) {
411→
412→        query = "%" + query + "%";
413→
414→        Uri queryUri = Email.CONTENT_URI;
415→
416→        String selection = Contacts.DISPLAY_NAME_PRIMARY + " LIKE ? " +
417→                " OR (" + Email.ADDRESS + " LIKE ? AND " + Data.MIMETYPE + " = '" + Email.CONTENT_ITEM_TYPE + "')";
418→        String[] selectionArgs = { query, query };
419→
420→        Cursor cursor = null;
421→        if (hasContactPermission()) {
422→            cursor = contentResolver.query(queryUri, PROJECTION, selection, selectionArgs, SORT_ORDER);
423→        }
424→
425→        if (cursor == null) {
426→            return false;
427→        }
428→
429→        fillContactDataFromCursor(cursor, recipients, recipientMap);
430→
431→        return true;
432→
433→    }
434→
435→    private void fillContactDataFromCursor(Cursor cursor, List<Recipient> recipients,
436→            Map<String, Recipient> recipientMap) {
437→        fillContactDataFromCursor(cursor, recipients, recipientMap, null);
438→    }
