217→        int length = addressList.length();
218→        int pairStartIndex = 0;
219→        int pairEndIndex = 0;
220→        int addressEndIndex = 0;
221→        while (pairStartIndex < length) {
222→            pairEndIndex = addressList.indexOf(",\u0001", pairStartIndex);
223→            if (pairEndIndex == -1) {
224→                pairEndIndex = length;
225→            }
226→            addressEndIndex = addressList.indexOf(";\u0001", pairStartIndex);
227→            String address = null;
