 25→ * address list fields, and also provides a method for converting
 26→ * a string of addresses (such as might be typed into such a field)
 27→ * into a series of Rfc822Tokens.
 28→ */
 29→public class Rfc822Tokenizer {
 30→
 31→    /**
 32→     * This constructor will try to take a string like
 33→     * "Foo Bar (something) &lt;foo\@google.com&gt;,
 34→     * blah\@google.com (something)"
 35→     * and convert it into one or more Rfc822Tokens, output into the supplied
 36→     * collection.
 37→     *
 38→     * It does *not* decode MIME encoded-words; charset conversion
 39→     * must already have taken place if necessary.
 40→     * It will try to be tolerant of broken syntax instead of
 41→     * returning an error.
 42→     *
 43→     */
 44→    public static void tokenize(CharSequence text, Collection<Rfc822Token> out) {
 45→        StringBuilder name = new StringBuilder();
 46→        StringBuilder address = new StringBuilder();
 47→        StringBuilder comment = new StringBuilder();
 48→
 49→        int i = 0;
 50→        int cursor = text.length();
 51→
 52→        while (i < cursor) {
 53→            char c = text.charAt(i);
 54→
 55→            if (c == ',' || c == ';') {
 56→                i++;
 57→
 58→                while (i < cursor && text.charAt(i) == ' ') {
 59→                    i++;
 60→                }
 61→
 62→                crunch(name);
 63→
 64→                if (address.length() > 0) {
 65→                    out.add(new Rfc822Token(name.toString(),
 66→                            address.toString(),
 67→                            comment.toString()));
 68→                } else if (name.length() > 0) {
 69→                    out.add(new Rfc822Token(null,
 70→                            name.toString(),
 71→                            comment.toString()));
 72→                }
 73→
 74→                name.setLength(0);
 75→                address.setLength(0);
 76→                comment.setLength(0);
 77→            } else if (c == '"') {
 78→                i++;
 79→
 80→                while (i < cursor) {
 81→                    c = text.charAt(i);
 82→
 83→                    if (c == '"') {
 84→                        i++;
 85→                        break;
 86→                    } else if (c == '\\') {
 87→                        if (i + 1 < cursor) {
 88→                            name.append(text.charAt(i + 1));
 89→                        }
 90→                        i += 2;
 91→                    } else {
 92→                        name.append(c);
 93→                        i++;
 94→                    }
 95→                }
 96→            } else if (c == '(') {
 97→                int level = 1;
 98→                i++;
 99→
100→                while (i < cursor && level > 0) {
101→                    c = text.charAt(i);
102→
103→                    if (c == ')') {
104→                        if (level > 1) {
105→                            comment.append(c);
106→                        }
107→
108→                        level--;
109→                        i++;
110→                    } else if (c == '(') {
111→                        comment.append(c);
112→                        level++;
113→                        i++;
114→                    } else if (c == '\\') {
115→                        if (i + 1 < cursor) {
116→                            comment.append(text.charAt(i + 1));
117→                        }
118→                        i += 2;
119→                    } else {
120→                        comment.append(c);
121→                        i++;
122→                    }
123→                }
124→            } else if (c == '<') {
125→                i++;
126→
127→                while (i < cursor) {
128→                    c = text.charAt(i);
129→
130→                    if (c == '>') {
131→                        i++;
132→                        break;
133→                    } else {
134→                        address.append(c);
135→                        i++;
136→                    }
137→                }
138→            } else if (c == ' ') {
139→                name.append('\0');
140→                i++;
141→            } else {
142→                name.append(c);
143→                i++;
144→            }
145→        }
