176→    private static void crunch(StringBuilder sb) {
177→        int i = 0;
178→        int len = sb.length();
179→
180→        while (i < len) {
181→            char c = sb.charAt(i);
182→
183→            if (c == '\0') {
184→                if (i == 0 || i == len - 1 ||
185→                        sb.charAt(i - 1) == ' ' ||
186→                        sb.charAt(i - 1) == '\0' ||
187→                        sb.charAt(i + 1) == ' ' ||
188→                        sb.charAt(i + 1) == '\0') {
189→                    sb.deleteCharAt(i);
190→                    len--;
191→                } else {
192→                    i++;
193→                }
194→            } else {
195→                i++;
196→            }
197→        }
198→
199→        for (i = 0; i < len; i++) {
200→            if (sb.charAt(i) == '\0') {
201→                sb.setCharAt(i, ' ');
202→            }
203→        }
204→    }
