209→    public int findTokenStart(CharSequence text, int cursor) {
210→        /*
211→         * It's hard to search backward, so search forward until
212→         * we reach the cursor.
213→         */
214→
215→        int best = 0;
216→        int i = 0;
217→
218→        while (i < cursor) {
219→            i = findTokenEnd(text, i);
220→
221→            if (i < cursor) {
222→                i++; // Skip terminating punctuation
223→
224→                while (i < cursor && text.charAt(i) == ' ') {
225→                    i++;
226→                }
227→
228→                if (i < cursor) {
229→                    best = i;
230→                }
231→            }
232→        }
233→
234→        return best;
235→    }
