237→    /**
238→     * {@inheritDoc}
239→     */
240→    public int findTokenEnd(CharSequence text, int cursor) {
241→        int len = text.length();
242→        int i = cursor;
243→
244→        while (i < len) {
245→            char c = text.charAt(i);
246→
247→            if (c == ',' || c == ';') {
248→                return i;
249→            } else if (c == '"') {
250→                i++;
251→
252→                while (i < len) {
253→                    c = text.charAt(i);
254→
255→                    if (c == '"') {
256→                        i++;
257→                        break;
258→                    } else if (c == '\\' && i + 1 < len) {
259→                        i += 2;
260→                    } else {
261→                        i++;
262→                    }
263→                }
264→            } else if (c == '(') {
265→                int level = 1;
266→                i++;
267→
268→                while (i < len && level > 0) {
269→                    c = text.charAt(i);
270→
271→                    if (c == ')') {
272→                        level--;
273→                        i++;
274→                    } else if (c == '(') {
275→                        level++;
276→                        i++;
277→                    } else if (c == '\\' && i + 1 < len) {
278→                        i += 2;
279→                    } else {
280→                        i++;
281→                    }
282→                }
283→            } else if (c == '<') {
284→                i++;
285→
286→                while (i < len) {
287→                    c = text.charAt(i);
288→
289→                    if (c == '>') {
290→                        i++;
291→                        break;
292→                    } else {
293→                        i++;
294→                    }
295→                }
296→            } else {
297→                i++;
298→            }
299→        }
300→
301→        return i;
302→    }
